class Solution {
    private int[] heights;
    private int rows, cols;
    private HashMap<String,Integer> dp = new HashMap<>();
    public int tilingRectangle(int n, int m) {
        rows = n;
        cols = m;
        if(rows == cols) return 1;
        if(rows%cols == 0){
            return (int)(rows/cols);
        }
        if(cols%rows == 0){
            return (int)(cols/rows);
        }
        //default values will be 0
        heights = new int[cols];
        dp.clear();
        int minTileCount = fillSquareWithTiles();
        return minTileCount;
    }

    private int fillSquareWithTiles(){
        //Limit - rows, cols <= 13
        String s = "";
        for(int i = 0; i<heights.length; ++i){
            s += String.valueOf(heights[i]+",");
        }

        Integer value = dp.get(s);
        if(value!=null) return value;
        //minHeight will have minHeight of skyline or filled matrix with tiles
        int minHeight = rows;
        int tileCount = Integer.MAX_VALUE;
        //start and end will be the starting and ending positions of region in 
        //square where height is minimum for current state.
        int start = 0, end = cols - 1;
        //Finding minHeight and start value
        for(int i = 0; i<heights.length; ++i){
            if(heights[i]<minHeight){
                start = i;
                minHeight = heights[i];
            }
            if(heights[i] == minHeight){
                end = i;
            }
        }

        //End condition, when there is no room for further tiles
        if(minHeight == rows){
            return 0;
        }
        //Finding end value for minHeight
        //Finding end above

        //Filling minHeight region with squares of different lengths
        for(int i = start ; i<=end; ++i){

            int squareLength = i - start + 1;
            //Current tile of size squareLength won't fit in matrix
            if(minHeight + squareLength > rows) {
                break;
            }

            //Filling current heights[] with squareLength to raise the skyline 
            //betwen start and end indices
            for(int j = start; j<=i; ++j){
                heights[j] += squareLength;
            }
            int count = fillSquareWithTiles();
            if(count < Integer.MAX_VALUE){
                tileCount = Math.min(tileCount,1 + count);
            }

            //Decreasing current heights[] with squareLength to reduce the skyline to original
            //between start and end indices
            for(int j = start; j<=i; ++j){
                heights[j] -= squareLength;
            }
        }


        dp.put(s,tileCount);

        return tileCount;
    }
}
